code = """import json
import os
import re

# Read the results from storage files
with open('var_functions.query_db:10.json', 'r') as f:
    children_books = json.load(f)

with open('var_functions.query_db:6.json', 'r') as f:
    reviews_2020 = json.load(f)

print(f"Loaded {len(children_books)} children's books")
print(f"Loaded {len(reviews_2020)} reviews from 2020 onwards")

# Show sample data
print("\nSample children's books:")
for book in children_books[:3]:
    print(f"  {book}")

print("\nSample reviews:")
for review in reviews_2020[:3]:
    print(f"  {review}")

# Create mappings
book_map = {}
for book in children_books:
    book_id = book['book_id']
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        num_id = match.group(1)
        book_map[num_id] = book

reviews_by_book = {}
for review in reviews_2020:
    purchase_id = review['purchase_id']
    match = re.search(r'purchaseid_(\d+)', purchase_id)
    if match:
        num_id = match.group(1)
        if num_id not in reviews_by_book:
            reviews_by_book[num_id] = []
        reviews_by_book[num_id].append(float(review['rating']))

print(f"\nBooks with matching reviews: {len(set(book_map.keys()) & set(reviews_by_book.keys()))}")

result = {
    "books_loaded": len(children_books),
    "reviews_loaded": len(reviews_2020),
    "books_with_reviews": len(set(book_map.keys()) & set(reviews_by_book.keys()))
}

print('__RESULT__:')
print(json.dumps(result))"""

